\begin{lemma} \label{lemma_mul_momentum}
If $\rho \in (-1,1)$ and
    $$
\begin{pmatrix}
X \\ Y \\ Z \\ W
\end{pmatrix}
\sim \mathcal{N}\!\left(
\begin{pmatrix}
0 \\ 0 \\ 0 \\ 0
\end{pmatrix},
\,
\sigma^2
\begin{pmatrix}
1      & \rho & \rho & \rho \\
\rho   & 1    & \rho & \rho \\
\rho   & \rho & 1    & \rho \\
\rho   & \rho & \rho & 1
\end{pmatrix}
\right),
$$
then, 
\begin{align*}
    \EE[X \vee Y] =  \sigma \sqrt{\frac{1-\rho}{\pi}}, \quad
\EE[(X \vee Y)^2] = \sigma^2, \quad
\EE[(X \vee Y)(Z \vee W)] = \left(\rho + \frac{1-\rho}{\pi} \right) \sigma^2.
\end{align*}
\end{lemma}

